// Create a MongoDB collection for user tokens
const mongoose = require('mongoose');
const userSchema = new mongoose.Schema({
  userId: String,
  token: String,
  expiresAt: Date,
  createdAt: Date
});

const UserToken = mongoose.model('UserToken', userSchema);

// Create a new user token
async function createUserToken(userId, token, expiresAt) {
  const userToken = new UserToken({
    userId,
    token,
    expiresAt,
    createdAt: new Date()
  });
  await userToken.save();
  return userToken;
}

// Get a user token by user ID
async function getUserToken(userId) {
  return await UserToken.findOne({ userId });
}

// Update a user token
async function updateUserToken(userId, token, expiresAt) {
  return await UserToken.updateOne({ userId }, {
    $set: {
      token,
      expiresAt
    }
  });
}

// Delete a user token
async function deleteUserToken(userId) {
  return await UserToken.deleteOne({ userId });
}

